package com.veetu.vadagai.auth;import com.veetu.vadagai.user.UserRepository;import lombok.RequiredArgsConstructor;import org.springframework.security.core.userdetails.*;import org.springframework.stereotype.Service;
@Service @RequiredArgsConstructor public class CustomUserDetailsService implements UserDetailsService{private final UserRepository users;public UserDetails loadUserByUsername(String email){var u=users.findByEmailIgnoreCaseAndDeletedFalse(email).orElseThrow(()->new UsernameNotFoundException(email));return org.springframework.security.core.userdetails.User.withUsername(u.getEmail()).password(u.getPasswordHash()).disabled(!u.isEmailVerified()).accountLocked(u.isAccountLocked()).authorities(u.getRoles().stream().map(r->"ROLE_"+r.name()).toArray(String[]::new)).build();}}
